mapper.select:
/* selectAdmin1002List */ SELECT dm.dept_mmbr_oid, dm.dept_oid, d.dept_nm, dm.user_nm, dm.telno, dm.jbgd, dm.indct_seq, dm.chrg_job, dm.reg_id, dm.reg_dt, dm.mdfcn_id, dm.mdfcn_dt FROM ${schema}.dept_mmbr dm INNER JOIN ${schema}.dept d ON dm.dept_oid = d.dept_oid
AND dm.dept_oid = #{deptOid}
AND dm.user_nm LIKE CONCAT('%', #{userNm}, '%')
AND dm.jbgd LIKE CONCAT('%', #{jbgd}, '%')
AND dm.chrg_job = #{chrgJob}
ORDER BY dm.indct_seq, dm.chrg_job DESC, dm.user_nm

